// Parse the hub's SSE-framed JSON-RPC reply; emit a notification payload only if approvals pend.
const raw = $input.first().json.data ?? $input.first().json.body ?? '';
const line = String(raw).split('\n').find((l) => l.startsWith('data:')) ?? '';
const rpc = JSON.parse(line.slice(5).trim());
if (rpc.result?.isError) throw new Error(rpc.result.content?.[0]?.text ?? 'tool error');
const approvals = JSON.parse(rpc.result?.content?.[0]?.text ?? '[]');
if (!Array.isArray(approvals) || approvals.length === 0) return []; // nothing pending -> stop
const subjects = approvals.map((a) => a.subject ?? a.id).slice(0, 10);
return [{ json: { count: approvals.length, subjects } }];

const raw = $input.first().json.data ?? $input.first().json.body ?? '';
const line = String(raw).split('\n').find((l) => l.startsWith('data:')) ?? '';
const rpc = JSON.parse(line.slice(5).trim());
if (rpc.result?.isError) throw new Error(rpc.result.content?.[0]?.text ?? 'notify failed');
return [{ json: { ok: true } }];
